397	// readTreeHeadWithRetry runs `git read-tree HEAD` in dir, retrying with
398	// exponential backoff when the git index lock is held by a concurrent process.
399	//
400	// Background (ddx-7e659c95): git read-tree needs to acquire .git/index.lock.
401	// When an operator git command (git status, git commit, etc.) holds the lock
402	// concurrently, git exits 128 with "Unable to create index.lock: File exists".
403	// Without retry the main worktree index stays dirty after a merge landing,
404	// causing a subsequent `git commit beads.jsonl` to sweep in phantom reverts of
405	// the bead's changes.
406	//
407	// The retry budget (30 s, 100 ms → 1 s backoff) matches the
408	// DefaultLockRetryPolicy used by withTrackerLock so contention handling is
409	// consistent across all ddx git-index operations.
410	func readTreeHeadWithRetry(dir string) ([]byte, error) {
411		const (
412			initialBackoff = 100 * time.Millisecond
413			maxBackoff     = 1 * time.Second
414			maxElapsed     = 30 * time.Second
415		)
416		start := time.Now()
417		backoff := initialBackoff
418		for {
419			out, err := internalgit.Command(context.Background(), dir, "read-tree", "HEAD").CombinedOutput()
420			if err == nil {
421				return out, nil
422			}
423			// Only retry on index lock contention; all other errors are fatal.
424			if !strings.Contains(string(out), "index.lock") {
425				return out, err
426			}
427			if time.Since(start) >= maxElapsed {
428				return out, err
429			}
430			time.Sleep(backoff)
431			backoff *= 2
432			if backoff > maxBackoff {
433				backoff = maxBackoff
434			}
435		}
436	}
